    def set_read_permission(self, user_id: int, file_path: str, can_read: bool) -> None:
        with self._connect() as conn:
            cur = conn.cursor()
            cur.execute(
                """
                INSERT INTO permissions (user_id, file_path, can_read)
                VALUES (?, ?, ?)
                ON CONFLICT(user_id, file_path)
                DO UPDATE SET can_read = excluded.can_read
                """,
                (user_id, file_path, 1 if can_read else 0),
            )
